import React, { useState, useEffect } from "react"
import { graphql, Link } from "gatsby"
import { globalHistory } from "@reach/router"
import SEO from "../components/seo"
import {
  Container,
  Collapse,
  Navbar,
  NavbarToggler,
  Nav,
  NavItem,
} from "reactstrap"
import List from "../components/blog-list"

const SearchTemplate = ({ data }) => {
  let { edges: posts } = data.allMarkdownRemark

  const [value, setValue] = useState("")

  const handleAddValue = e => {
    setValue(e.target.value)
  }
  var searchValue = value.trim().toLowerCase()

  if (searchValue.length > 0) {
    var searchposts = posts.filter(l => {
      return (
        l.node.frontmatter.title.toLowerCase().match(searchValue) ||
        l.node.html.toLowerCase().match(searchValue)
      )
    })
  }

  // State of our Menu
  const [state, setState] = useState({
    initial: false,
    clicked: null,
  })

  // Toggle menu
  const handleMenu = () => {
    if (state.initial === false) {
      setState({
        initial: null,
        clicked: true,
      })
    } else if (state.clicked === true) {
      setState({
        clicked: !state.clicked,
      })
    } else if (state.clicked === false) {
      setState({
        clicked: !state.clicked,
      })
    }
  }

  useEffect(() => {
    var body = document.querySelector("body")
    // If the menu is open and we click the menu button to close it.
    if (state.clicked === false) {
      // If menu is closed and we want to open it.
      body.classList.remove("nav-active")
    } else if (
      state.clicked === true ||
      (state.clicked === true && state.initial === null)
    ) {
      body.classList.add("nav-active")
    }
    //Listening for page changes.
    globalHistory.listen(() => {
      setState({ clicked: false })
      console.log("clicked-menu")
    })
  })

  return (
    <>
      <SEO title={value || "Search Page"} />

      <div class="nav">
        <div class="nav__content">
          <div class="container">
            <ul class="nav__list p-4 p-lg-0">
            <div className="overflow-hidden">
              <li class="nav__list-item active-nav">
                <Link className="hover-target" to="/">
                  Home
                </Link>
              </li>
              </div>
            <div className="overflow-hidden">
              <li class="nav__list-item">
                <Link className="hover-target" to="/blog">
                  Blog
                </Link>
              </li>
              </div>
              {/* <li class="nav__list-item"><a href="#" class="hover-target">About</a></li> */}
            <div className="overflow-hidden">
              <li class="nav__list-item">
                <Link className="hover-target" to="/search">
                  Search
                </Link>
              </li>
              </div>
            </ul>
          </div>
        </div>
      </div>
      <Navbar
        className="navbar navbar-expand-lg navbar-light p-5"
        style={{
          zIndex:'1030'
        }}
        id="mainNav"
      >
        <Nav className="ml-auto" navbar>
          <NavItem onClick={handleMenu}>
            <div class="nav-link menu-icon hover-target">
              <span class="menu-icon__line menu-icon__line-left"></span>
              <span class="menu-icon__line"></span>
              <span class="menu-icon__line menu-icon__line-right"></span>
            </div>
          </NavItem>
        </Nav>
      </Navbar>
      
      <Container>
        <h1 className="mt-0" style={{ border: "unset", fontSize:'6vw' }}>
          <input
            type="text"
            value={value}
            onChange={handleAddValue}
            placeholder="Type here"
            autoFocus
          />
        </h1>
        <div className="blog-posts">
          {searchposts
            ? searchposts
                .filter(post => post.node.frontmatter.title.length > 0)
                .map(({ node: post }) => {
                  const { excerpt, id } = post
                  const { title, path, date, tags } = post.frontmatter
                  return (
                    <List data={{ title, path, date, tags, excerpt, id }} />
                  )
                })
            : null}
        </div>
      </Container>
    </>
  )
}

export default SearchTemplate

export const searchListQuery = graphql`
  query BlogQuery {
    allMarkdownRemark(sort: { order: DESC, fields: [frontmatter___date] }) {
      edges {
        node {
          excerpt(pruneLength: 250)
          id
          html
          frontmatter {
            title
            date(formatString: "DD MMM YY")
            path
            tags
          }
        }
      }
    }
  }
`
